<template>
  <v-list-item>
    <v-list-item-content>
      <v-list-item-title>
        <div class="d-flex align-center">
          <v-checkbox
            v-model="isChecked"
            :label="localSection.label"
            :color="localSection.color || 'primary'"
            :disabled="!parentChecked"
            @change="onCheckboxChange"
          />
          <v-btn
            v-if="localSection.children && localSection.children.length > 0"
            @click="toggleCollapse"
            icon
            small
            class="ml-2"
          >
            <v-icon small>{{ localSection.collapsed ? 'mdi-chevron-right' : 'mdi-chevron-down' }}</v-icon>
          </v-btn>
        </div>
      </v-list-item-title>
      <!-- Render children if any -->
      <v-list dense>
        <div v-if="localSection.children && !localSection.collapsed">
          <SectionCheckbox
            v-for="child in localSection.children"
            :key="child.id"
            :section="child"
            :indent="indent + 20"
            :parent-checked="isChecked"
            :all-collapsed="allCollapsed"
            @update-checked="emitUpdateChecked"
          />
        </div>
      </v-list>
    </v-list-item-content>
  </v-list-item>
</template>

<script>
export default {
  name: 'SectionCheckbox',
  components: {
    SectionCheckbox: () => import('./SectionCheckbox.vue'), // Ensure recursive component is registered
  },
  props: {
    section: Object,
    indent: {
      type: Number,
      default: 0,
    },
    parentChecked: {
      type: Boolean,
      default: true,
    },
    allCollapsed: {
      type: Boolean,
      default: false,
    },
  },
  data() {
    return {
      isChecked: this.section.checked,
      localSection: { 
        ...this.section, 
        collapsed: this.section.collapsed || false 
      }, // Ensure collapsed is defined
    };
  },
  watch: {
    'section.checked': {
      immediate: true,
      handler(newVal) {
        this.isChecked = newVal;
      },
    },
    'section.color': {
      immediate: true,
      handler(newVal) {
        this.localSection.color = newVal; // Update color when prop changes
      },
    },
    allCollapsed: {
      immediate: true,
      handler(newVal) {
        this.localSection.collapsed = newVal; // Collapse/expand all sections
      },
    },
    isChecked(newVal) {
      if (!newVal && this.localSection.children) {
        this.localSection.children.forEach((child) => {
          child.checked = false;
        });
      }
    },
  },
  emits: ['update-checked'],
  methods: {
    onCheckboxChange() {
      this.$emit('update-checked', { id: this.localSection.id, checked: this.isChecked });

      if (!this.isChecked && this.localSection.children) {
        this.localSection.children.forEach((child) => {
          child.checked = false;
        });
      }
    },
    toggleCollapse() {
      this.localSection.collapsed = !this.localSection.collapsed; // Toggle collapse
    },
    emitUpdateChecked(payload) {
      this.$emit('update-checked', payload);
    },
  },
};
</script>

<style scoped>
.ml-2 {
  margin-left: 8px; /* Adjust spacing between checkbox and collapse button */
}

.v-list-item {
  padding-left: 0; /* Remove default padding */
}

.v-checkbox {
  margin-left: 0; /* Align checkbox to the left */
}

.v-icon {
  font-size: 18px; /* Adjust the icon size */
}
</style>
