<template>
  <AppBarLayout>
    <v-container fluid>
      <!-- v-snackbar is now handled globally in AppBarLayout.vue -->
      
      <v-row
        v-for="(table, tableIndex) in filteredTables"
        :key="tableIndex"
        class="table-section"
      >
        <v-col cols="12">
          <v-card class="elevated-card">
            <v-card-title class="card-header">
              {{ formatTableName(table.name) }}
              <v-spacer></v-spacer>
              <v-btn
                v-if="table.hyperlink"
                icon
                @click="navigateTo(table.hyperlink.url)"
                :title="table.hyperlink.label"
                class="table-hyperlink-button"
              >
                <v-icon color="white">mdi-link</v-icon>
              </v-btn>
            </v-card-title>
            <v-divider></v-divider>
            <v-simple-table class="styled-table">
              <thead>
                <tr>
                  <th v-for="header in table.headers" :key="header">
                    {{ header }}
                  </th>
                </tr>
              </thead>
              <tbody>
                <tr
                  v-for="(row, rowIndex) in table.rows"
                  :key="rowIndex"
                  class="table-row"
                >
                  <td
                    v-for="(cell, colIndex) in row"
                    :key="colIndex"
                    :colspan="cell.colspan"
                    :rowspan="cell.rowspan"
                  >
                    <template v-if="cell.isPlaceholder">
                      <v-text-field
                        v-model="cell.value"
                        :label="cell.id"
                        variant="outlined"
                        dense
                        class="table-cell-input"
                        hide-details
                      />
                    </template>
                    <template v-else>
                      <span>{{ cell.content }}</span>
                    </template>
                  </td>
                </tr>
              </tbody>
            </v-simple-table>
          </v-card>
        </v-col>
      </v-row>

      <v-row class="button-row">
        <v-btn
          @click="navigateToCheckboxPage"
          color="success"
          large
          class="action-button"
        >
          Next
        </v-btn>
      </v-row>
    </v-container>
  </AppBarLayout>
</template>

<script>
import { ref, onMounted, computed } from 'vue';
import { useStore } from 'vuex';
import { useRouter, onBeforeRouteLeave } from 'vue-router';
import axios from 'axios';
import AppBarLayout from './AppBarLayout.vue';

export default {
  components: {
    AppBarLayout, // Register AppBarLayout
  },
  setup() {
    const store = useStore();
    const router = useRouter();
    const tables = ref([]);
    
    /**
     * Optional function to log cell updates
     * Can be expanded to perform additional actions on input
     * @param {Object} cell - The cell object being updated
     */
    const logCellUpdate = (cell) => {
      console.log(`Cell updated: ${cell.id} = ${cell.value}`);
      // Optionally, persist the updated cell value to Vuex or perform validation
    };

    /**
     * Load persisted table values from Vuex store
     */
    const loadPersistedTableValues = () => {
      console.log("Loading persisted structured table from Vuex...");
      tables.value = store.state.structuredTableData || [];
    };

    const filteredTables = computed(() => {
      return tables.value.map((table) => {
        const filteredRows = table.rows.map((row) => {
          const seenMergedCells = new Set(); // Track unique merged cells
          return row
            .filter((cell) => cell) // Remove null cells
            .filter((cell) => {
              // Skip duplicate merged cells (colspan > 1)
              if (cell.colspan > 1 && seenMergedCells.has(cell.content)) {
                return false;
              }

              if (cell.colspan > 1) {
                seenMergedCells.add(cell.content);
              }

              return true; // Keep the cell
            });
        });

        return {
          ...table,
          rows: filteredRows,
        };
      });
    });

    /**
     * Fetch and parse tables and tags from the document template
     */
    const loadDynamicTables = async () => {
      const selectedTemplate = store.state.selectedTemplate;

      if (!selectedTemplate || !selectedTemplate.fileId || !selectedTemplate.bucketName) {
        alert("No valid template selected. Please go back and select a template.");
        router.push({ name: "userOptionsPage" });
        return;
      }

      const { fileId, bucketName } = store.state.selectedTemplate;
      const hasPersistedData = store.state.structuredTableData.length > 0;

      if (!store.state.isNavigatingBack || !hasPersistedData) {
        console.log("Fetching template data for tables and tags...");
        try {
          console.log("Sending to Flask:", { fileId, bucketName });

          // Fetch table data and tags from the Flask backend
          const response = await axios.get("http://192.168.50.57:5000/api/parse-document", {
            params: {
              fileId,
              bucketName,
            },
          });

          console.log("Response from Flask:", response.data);

          const { tables: parsedTables, tags } = response.data;

          // Save parsed tables and tags to Vuex
          store.dispatch("saveStructuredTableData", parsedTables);
          store.dispatch("saveCollatedTags", tags);

          // Set tables to the component state
          tables.value = parsedTables;

          console.log("Template tables loaded:", tables.value);
          console.log("Collated tags saved to Vuex:", tags);

          // Check if no tables are present
          if (parsedTables.length === 0) {
            // Show Snackbar and navigate after 3 seconds
            store.dispatch("showSnackbar", "No tables detected. Proceeding to the next step...");

            setTimeout(() => {
              router.push({ name: "checkboxPage" }); // Replace with your next page route
            }, 3000);
          }
        } catch (error) {
          console.error("Error fetching or parsing template data:", error);
          alert("Failed to load dynamic table data. Please try again later.");
        }
      } else {
        console.log("Navigating back: Loading persisted structured table data...");
        loadPersistedTableValues();
      }

      store.commit("setNavigatingBack", false);
    };

    /**
     * Build the final data object for Docxtemplater
     * @returns {Object} - The data object mapping placeholder IDs to user inputs
     */
    const buildDocxtemplaterData = () => {
      console.log('Starting to build data object from table:', tables.value);
      const dataForDocxtemplater = {};

      // Loop through each table to gather data
      tables.value.forEach((table) => {
        table.rows.forEach((row) => {
          row.forEach((cell) => {
            if (cell && cell.isPlaceholder && cell.id) {
              // Map the placeholder ID to the user-entered value
              dataForDocxtemplater[cell.id] = cell.value;
            }
          });
        });
      });

      console.log('Data for Docxtemplater:', dataForDocxtemplater);
      return dataForDocxtemplater;
    };

    const exportTablesData = () => {
      const dataStr = JSON.stringify(tables.value, null, 2); // Convert tables to JSON string
      const blob = new Blob([dataStr], { type: 'application/json' }); // Create a Blob object
      const url = URL.createObjectURL(blob); // Create a URL for the Blob

      const a = document.createElement('a'); // Create an anchor element
      a.href = url;
      a.download = 'tables_debug.json'; // File name for download
      a.click(); // Trigger the download

      URL.revokeObjectURL(url); // Clean up the URL object
    };

    /**
     * Navigate to CheckboxPage.vue after collecting data
     */
    const navigateToCheckboxPage = () => {
      const docxtemplaterData = buildDocxtemplaterData();

      store.dispatch("saveTableData", docxtemplaterData); // Flattened data for Docxtemplater
      // Optionally, if you need to save structured data separately:
      // store.dispatch("saveStructuredTableData", tables.value);

      console.log("Saved table data to Vuex:", docxtemplaterData);
      router.push({ name: "checkboxPage" });
    };

    /**
     * Format the table name for display (e.g., "table_name" to "Table Name")
     * @param {String} name - The original table name
     * @returns {String} - The formatted table name
     */
    const formatTableName = (name) => {
      return name
        .replace(/_/g, ' ')
        .replace(/\b\w/g, (c) => c.toUpperCase());
    };

    /**
     * Open a hyperlink in a new browser tab
     * @param {String} url - The URL to navigate to
     */
    const navigateTo = (url) => {
      window.open(url, '_blank'); // Opens the link in a new tab
    };

    onMounted(() => {
      loadDynamicTables();
    });

    onBeforeRouteLeave((to, from, next) => {
      store.commit('setNavigatingBack', true); // Set isNavigatingBack to true when navigating away
      next(); // Allow the navigation to proceed
    });

    return {
      tables, 
      filteredTables,
      navigateTo,
      navigateToCheckboxPage,
      formatTableName,
      logCellUpdate,
      exportTablesData,
      // Remove local snackbar refs if using global
      // showSnackbar,
      // snackbarMessage,
    };
  },
};
</script>


<style scoped>
/* General Styling */
.v-app-bar {
  font-weight: bold;
}

.table-section {
  margin-bottom: 24px;
}

/* Elevated Cards with Shadows */
.elevated-card {
  border-radius: 12px;
  box-shadow: 0 4px 10px rgba(0, 0, 0, 0.1);
  overflow: hidden;
}

/* Card Header Styling */
.card-header {
  background-color: #0f6554; /* Vibrant green */
  color: white;
  font-weight: bold;
  display: flex;
  align-items: center;
}

/* Styled Table */
.styled-table {
  margin-top: 16px;
}

.styled-table th {
  background-color: #00796b; /* Muted teal */
  color: white;
  font-size: 14px;
  font-weight: bold;
  text-align: center;
  padding: 12px;
  border-bottom: 2px solid #004d40;
}

.styled-table td {
  padding: 12px;
  border: 1px solid #ddd;
}

.styled-table tr:nth-child(even) {
  background-color: #f9f9f9;
}

.styled-table tr:hover {
  background-color: #e0f7fa;
}

/* Input Field in Table Cells */
.table-cell-input {
  margin: 0;
  font-size: 14px;
  width: 100%;
}

/* Button Row */
.button-row {
  margin-top: 32px;
  justify-content: center;
}

.action-button {
  margin: 0 8px;
  border-radius: 24px;
}
</style>